function getPricing(modelName) {
  const lower = modelName.toLowerCase();
  const sortedKeys = Object.keys(MODEL_PRICING).sort((a, b) => b.length - a.length);
  for (const key of sortedKeys) {
    if (lower.includes(key.toLowerCase())) {
      return MODEL_PRICING[key];
    }
  }
  return null;
}
class CostTracker {
  constructor() {
    this.session = {
      inputTokens: 0,
      outputTokens: 0,
      cacheReadTokens: 0,
      cacheWriteTokens: 0,
      totalCostUSD: 0,
      model: ""
    };
  }
  addUsage(model, inputTokens, outputTokens, cacheReadTokens = 0, cacheWriteTokens = 0) {
    this.session.model = model;
    this.session.inputTokens += inputTokens;
    this.session.outputTokens += outputTokens;
    this.session.cacheReadTokens += cacheReadTokens;
    this.session.cacheWriteTokens += cacheWriteTokens;
    const pricing = getPricing(model);
    if (pricing) {
      const inputCost = inputTokens / 1e6 * pricing.inputPerMToken;
      const outputCost = outputTokens / 1e6 * pricing.outputPerMToken;
      const cacheRead = cacheReadTokens / 1e6 * (pricing.cacheReadPerMToken ?? 0);
      const cacheWrite = cacheWriteTokens / 1e6 * (pricing.cacheWritePerMToken ?? 0);
      this.session.totalCostUSD += inputCost + outputCost + cacheRead + cacheWrite;
    }
  }
  getSession() {
    return { ...this.session };
  }
  resetSession() {
    this.session = {
      inputTokens: 0,
      outputTokens: 0,
      cacheReadTokens: 0,
      cacheWriteTokens: 0,
      totalCostUSD: 0,
      model: ""
    };
  }
  /**
   * Returns a compact string like "$0.0123 | 45.2K tok"
   * for display in the status bar.
   */
  formatDisplay() {
    const cost = this.session.totalCostUSD;
    const total = this.session.inputTokens + this.session.outputTokens;
    const tokStr = total >= 1e3 ? `${(total / 1e3).toFixed(1)}K tok` : `${total} tok`;
    const costStr = `$${cost.toFixed(4)}`;
    return `${costStr} | ${tokStr}`;
  }
}
